"use server";

import { cookies, headers } from "next/headers";
import { redirect } from "next/navigation";

import { loadRhapsodyAuthSecretEnv } from "@/lib/config";
import {
	buildAdminSessionCookie,
	createAdminSessionToken,
	isSecureRequest,
	sanitizeNextPath,
	verifyAdminPassword,
} from "@/lib/server/admin-session";

const INVALID_LOGIN_DELAY_MS = 250;

export async function loginAction(formData: FormData) {
	const submittedPassword = String(formData.get("password") ?? "");
	const nextPath = sanitizeNextPath(formData.get("next"));

	const { AUTH_SECRET: authSecret } = loadRhapsodyAuthSecretEnv();
	const rootPassword = process.env.ROOT_PASSWORD ?? "";
	const requestHeaders = await headers();
	const secure = isSecureRequest(requestHeaders);

	if (!rootPassword?.trim() || !authSecret?.trim()) {
		await delay(INVALID_LOGIN_DELAY_MS);
		redirect("/login?error=configuration");
	}

	if (!verifyAdminPassword(submittedPassword, rootPassword)) {
		await delay(INVALID_LOGIN_DELAY_MS);
		redirect(`/login?error=invalid&next=${encodeURIComponent(nextPath)}`);
	}

	const sessionToken = createAdminSessionToken(authSecret);
	const cookieStore = await cookies();
	cookieStore.set(buildAdminSessionCookie(sessionToken, secure));

	redirect(nextPath);
}

function delay(ms: number) {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

