import { createHmac, timingSafeEqual } from "node:crypto";

export const ADMIN_SESSION_COOKIE_NAME = "rhapsody_admin_session";
const ADMIN_SESSION_TOKEN_PREFIX = "admin-session.";

export type AdminSessionCookie = {
	name: string;
	value: string;
	httpOnly: true;
	path: "/";
	sameSite: "lax";
	secure: boolean;
	maxAge: number;
};

export function sanitizeNextPath(value: FormDataEntryValue | null | undefined) {
	if (typeof value !== "string") {
		return "/dashboard";
	}

	if (!value.startsWith("/") || value.startsWith("//")) {
		return "/dashboard";
	}

	return value;
}

export function isSecureRequest(headers: Headers) {
	const forwardedProto = headers.get("x-forwarded-proto");

	if (forwardedProto) {
		return forwardedProto.split(",")[0]?.trim().toLowerCase() === "https";
	}

	return process.env.VERCEL_ENV === "production";
}

export function createAdminSessionToken(
	authSecret: string,
	issuedAt = Date.now(),
) {
	const nonce = createHmac("sha256", authSecret)
		.update(String(issuedAt))
		.digest("base64url");
	const payload = JSON.stringify({
		iat: issuedAt,
		nonce,
	});
	const payloadBase64 = base64UrlEncode(payload);
	const signature = createHmac("sha256", authSecret)
		.update(`${ADMIN_SESSION_TOKEN_PREFIX}${payloadBase64}`)
		.digest("base64url");

	return `${ADMIN_SESSION_TOKEN_PREFIX}${payloadBase64}.${signature}`;
}

export function verifyAdminPassword(
	submittedPassword: string,
	rootPassword: string,
) {
	const submitted = Buffer.from(submittedPassword);
	const expected = Buffer.from(rootPassword);
	const length = Math.max(submitted.length, expected.length, 1);
	const paddedSubmitted = Buffer.alloc(length);
	const paddedExpected = Buffer.alloc(length);

	submitted.copy(paddedSubmitted);
	expected.copy(paddedExpected);

	return timingSafeEqual(paddedSubmitted, paddedExpected);
}

export function buildAdminSessionCookie(
	token: string,
	secure: boolean,
): AdminSessionCookie {
	return {
		name: ADMIN_SESSION_COOKIE_NAME,
		value: token,
		httpOnly: true,
		path: "/",
		sameSite: "lax",
		secure,
		maxAge: 60 * 60 * 24 * 7,
	};
}

function base64UrlEncode(value: string) {
	return Buffer.from(value).toString("base64url");
}

