import { describe, expect, test } from "vitest";
import {
	buildAdminSessionCookie,
	createAdminSessionToken,
	isSecureRequest,
	sanitizeNextPath,
	verifyAdminPassword,
} from "./admin-session";

describe("admin session helpers", () => {
	test("sanitizes next path to an internal relative path", () => {
		expect(sanitizeNextPath("/dashboard")).toBe("/dashboard");
		expect(sanitizeNextPath("/dashboard/runs/123")).toBe("/dashboard/runs/123");
		expect(sanitizeNextPath("https://example.com")).toBe("/dashboard");
		expect(sanitizeNextPath("//example.com")).toBe("/dashboard");
		expect(sanitizeNextPath(null)).toBe("/dashboard");
	});

	test("detects secure requests from forwarded proto", () => {
		expect(isSecureRequest(new Headers({ "x-forwarded-proto": "https" }))).toBe(
			true,
		);
		expect(isSecureRequest(new Headers({ "x-forwarded-proto": "http" }))).toBe(
			false,
		);
		expect(
			isSecureRequest(new Headers({ "x-forwarded-host": "example.com" })),
		).toBe(false);
	});

	test("builds a secure cookie shape for session tokens", () => {
		const cookie = buildAdminSessionCookie("token", true);

		expect(cookie).toMatchObject({
			name: "rhapsody_admin_session",
			value: "token",
			httpOnly: true,
			path: "/",
			sameSite: "lax",
			secure: true,
		});
	});

	test("verifies passwords in constant-time compatible fashion", () => {
		expect(verifyAdminPassword("root", "root")).toBe(true);
		expect(verifyAdminPassword("root", "other")).toBe(false);
		expect(verifyAdminPassword("", "other")).toBe(false);
	});

	test("creates signed admin session tokens", () => {
		const token = createAdminSessionToken("secret", 1234);

		expect(token.startsWith("admin-session.")).toBe(true);
		expect(token.split(".")).toHaveLength(3);
	});
});

