import { createHmac, timingSafeEqual } from "node:crypto";

export const ADMIN_SESSION_COOKIE_NAME = "rhapsody_admin_session";
const ADMIN_SESSION_TOKEN_PREFIX = "admin-session.";
const ADMIN_SESSION_MAX_AGE_SECONDS = 60 * 60 * 24 * 7;

export type AdminSessionCookie = {
	name: string;
	value: string;
	httpOnly: true;
	path: "/";
	sameSite: "lax";
	secure: boolean;
	maxAge: number;
};

export type AdminSessionConfigError =
	| "ROOT_PASSWORD missing"
	| "AUTH_SECRET missing";

export function sanitizeNextPath(value: FormDataEntryValue | null | undefined) {
	if (typeof value !== "string") {
		return "/dashboard";
	}

	if (!value.startsWith("/") || value.startsWith("//")) {
		return "/dashboard";
	}

	return value;
}

export function isSecureRequest(headers: Headers) {
	const forwardedProto = headers.get("x-forwarded-proto");

	if (forwardedProto) {
		return forwardedProto.split(",")[0]?.trim().toLowerCase() === "https";
	}

	return process.env.VERCEL_ENV === "production";
}

export function hasAdminSessionConfig(env = process.env) {
	return Boolean(env.ROOT_PASSWORD?.trim() && env.AUTH_SECRET?.trim());
}

export function getAdminSessionConfigError(env = process.env) {
	if (!env.ROOT_PASSWORD?.trim()) {
		return "ROOT_PASSWORD missing" as const;
	}

	if (!env.AUTH_SECRET?.trim()) {
		return "AUTH_SECRET missing" as const;
	}

	return null;
}

export function createAdminSessionToken(
	authSecret: string,
	issuedAt = Date.now(),
) {
	const nonce = createHmac("sha256", authSecret)
		.update(String(issuedAt))
		.digest("base64url");
	const payload = JSON.stringify({
		iat: issuedAt,
		nonce,
	});
	const payloadBase64 = base64UrlEncode(payload);
	const signature = createHmac("sha256", authSecret)
		.update(`${ADMIN_SESSION_TOKEN_PREFIX}${payloadBase64}`)
		.digest("base64url");

	return `${ADMIN_SESSION_TOKEN_PREFIX}${payloadBase64}.${signature}`;
}

export function readAdminSessionTokenFromCookieStore(cookieStore: {
	get(name: string): { value: string } | undefined;
}) {
	return cookieStore.get(ADMIN_SESSION_COOKIE_NAME)?.value ?? null;
}

export function verifyAdminSessionToken(token: string, authSecret: string) {
	if (!token.startsWith(ADMIN_SESSION_TOKEN_PREFIX)) {
		return false;
	}

	const payloadAndSignature = token.slice(ADMIN_SESSION_TOKEN_PREFIX.length);
	const separatorIndex = payloadAndSignature.lastIndexOf(".");

	if (separatorIndex <= 0) {
		return false;
	}

	const payloadBase64 = payloadAndSignature.slice(0, separatorIndex);
	const signature = payloadAndSignature.slice(separatorIndex + 1);
	const expectedSignature = createHmac("sha256", authSecret)
		.update(`${ADMIN_SESSION_TOKEN_PREFIX}${payloadBase64}`)
		.digest("base64url");

	if (signature.length !== expectedSignature.length) {
		const dummy = Buffer.alloc(expectedSignature.length);
		timingSafeEqual(dummy, Buffer.alloc(expectedSignature.length));
		return false;
	}

	const signatureBytes = Buffer.from(signature);
	const expectedBytes = Buffer.from(expectedSignature);

	if (signatureBytes.length !== expectedBytes.length) {
		const dummy = Buffer.alloc(expectedBytes.length);
		timingSafeEqual(dummy, Buffer.alloc(expectedBytes.length));
		return false;
	}

	if (!timingSafeEqual(signatureBytes, expectedBytes)) {
		return false;
	}

	try {
		const payload = JSON.parse(
			Buffer.from(payloadBase64, "base64url").toString("utf8"),
		) as {
			iat?: unknown;
			nonce?: unknown;
		};

		return (
			typeof payload.iat === "number" &&
			Number.isFinite(payload.iat) &&
			typeof payload.nonce === "string" &&
			payload.nonce.length > 0
		);
	} catch {
		return false;
	}
}

export function verifyAdminPassword(
	submittedPassword: string,
	rootPassword: string,
) {
	const submitted = Buffer.from(submittedPassword);
	const expected = Buffer.from(rootPassword);

	if (submitted.length !== expected.length) {
		const length = Math.max(submitted.length, expected.length, 1);
		const paddedSubmitted = Buffer.alloc(length);
		const paddedExpected = Buffer.alloc(length);

		submitted.copy(paddedSubmitted);
		expected.copy(paddedExpected);
		timingSafeEqual(paddedSubmitted, paddedExpected);

		return false;
	}

	return timingSafeEqual(submitted, expected);
}

export function buildAdminSessionCookie(
	token: string,
	secure: boolean,
): AdminSessionCookie {
	return {
		name: ADMIN_SESSION_COOKIE_NAME,
		value: token,
		httpOnly: true,
		path: "/",
		sameSite: "lax",
		secure,
		maxAge: ADMIN_SESSION_MAX_AGE_SECONDS,
	};
}

function base64UrlEncode(value: string) {
	return Buffer.from(value).toString("base64url");
}

