			expect.objectContaining({
				name: "rhapsody_admin_session",
				httpOnly: true,
				path: "/",
				sameSite: "lax",
				secure: true,
				maxAge: 60 * 60 * 24 * 7,
			}),
		);
		expect(cookiesSet.mock.calls[0]?.[0]?.value).toMatch(
			/^admin-session\.[^.]+\.[^.]+$/,
		);
	});

